var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"하아, 하아, 하아……!","JPN":"はぁ、はぁ、はぁ……！","ENG":"*Huff* *Huff* *Huff…!*","TWN":"哈啊，哈啊，哈啊……！"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"크윽, 머리가…! 방금 그 기억은 뭐지…? 꿈인가……?","JPN":"くうっ、頭が……！　今の記憶は何……？　夢……？","ENG":"Argh, my head...! That memory just now... Was it a dream...?","TWN":"咳，頭好疼……！剛才的記憶是怎麼回事……？是夢嗎……？"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"아니야… 꿈이라기에는 너무나 선명해…….","JPN":"ううん……あんなに生々しかったんだ……とても夢とは……","ENG":"No... it felt too real to be a dream...","TWN":"不……這太清晰了，不像是夢……"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"마지막에는 마치, 내가 스완이 된 것 같은 느낌이었어……. 어떻게 된 거지?","JPN":"最後にはまるで、私がスワンになったような感覚だった……これって、どういうこと……？","ENG":"And at the end, it felt like I was Swan. What does that even mean?","TWN":"最後感覺，好像我變成了史旺……這是怎麼回事？"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아직 제정신을 유지하고 계시는군요.","JPN":"まだ正気を保っていますね。","ENG":"So, your mind's still intact.","TWN":"你還保持著清醒的頭腦啊。"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"……스완!","JPN":"……スワン！","ENG":"...Swan!","TWN":"……史旺！"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"뭐, 좋아요. 그래서 첫 각본은 어떠셨나요? 소감을 듣고 싶군요.","JPN":"まあ、いいでしょう。それで、最初の脚本はいかがでしたか？　感想をお聞かせ願います。","ENG":"Well then. How did you enjoy the first script? I'd love to hear your thoughts.","TWN":"嗯，好吧。那麼第一部劇本怎麼樣？我想聽聽你的感想。"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"대체 저한테 무슨 짓을 한 거죠?","JPN":"いったい私に何をしたんですか？","ENG":"What did you do to me?","TWN":"到底對我做了什麼？"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"당신이 보여준 그 세계… 그건 단순한 환각 같은 게 아니었어요!","JPN":"あなたが見せた世界……あれはただの幻覚なんかじゃなかった！","ENG":"That world you showed me... It wasn't just some illusion!","TWN":"你所展示的那個世界……那並不僅僅是幻覺！"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L18_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"그건 당신의 과거인가요? 그렇다면, 그 세계는 정말로 당신이……?","JPN":"あれはあなたの過去なんですか？　じゃあ、あの世界は本当にあなたが……？","ENG":"Was that... your past? Then that world was really...?","TWN":"那是你的過去嗎？如果是的話，那個世界真的是你……？"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"말씀드렸을 텐데요, 노엘.","JPN":"言ったはずです、ノエル。","ENG":"I told you already, Noelle.","TWN":"我應該說過，洛艾兒。"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 극장은 저의 완전 기억 능력이 클리파 차원의 허수 에너지를 통해 재구성된 공간.","JPN":"この劇場は、私の完全記憶能力がクリファ次元の虚数エネルギーによって再構築された空間。","ENG":"This theater is a space where my perfect memory ability is reconstructed by the Qlipha Dimension's Imaginary Energy.","TWN":"這個劇場是透過逆卡巴拉次元的虛數能量重構的空間，由我的完全記憶能力所創造。"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이 마주했던 세계는 암군이 으스러뜨린 수많은 세계 중 하나랍니다.","JPN":"あなたが目にした世界は、暗君によって潰された多くの世界の1つです。","ENG":"The world you saw is just one of many shattered by the Ignorant Monarch.","TWN":"你所面對的世界只是暗君摧毀的無數世界之一。"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"클리포트 게임에서 패배하여, 지금은 마왕의 클리파 차원에 귀속되어버린 세계죠.","JPN":"クリフォトゲームで敗北し、今は魔王のクリファ次元に囚われている世界です。","ENG":"It's a world that lost the Qliphoth Game... and now belongs to a Demon Lord's Qlipha Dimension.","TWN":"在逆卡巴拉遊戲中失敗，現在被歸屬于魔王的逆卡巴拉次元的世界。"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"말도 안 돼…….","JPN":"そんな……","ENG":"No way...","TWN":"這不可能……"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"제가 봤던 그 세계에서… 당신은 수없이 많은 사람들을 죽였잖아요…….","JPN":"私が見たあの世界で……あなたは数えきれないほどの人を殺した……","ENG":"In the world I saw... you killed so many people...","TWN":"在我所見過的那個世界裡……你殺了無數的人……"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"설마, 다른 세계에서도 그런 짓을 반복해 온 건가요? 대체 어째서……?","JPN":"まさか、他の世界でも同じことを繰り返してきたんですか？　いったいどうして……？","ENG":"Don't tell me you've done the same thing in other worlds too? Why would you do that...?","TWN":"難道，在其他世界也重複做那種事嗎？到底為什麼……？"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"물론, 그들에게 천사 강림을 시도하게끔 유도하기 위해서였답니다.","JPN":"もちろん彼らに天使の降臨を試させるためです。","ENG":"Simple. To push them into attempting the descent of an angel.","TWN":"當然，是為了引導他們嘗試召喚天使降臨。"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저는 무척이나 오랫동안 천사를 쫓아왔으니까요.","JPN":"私はとても長い間、天使を追ってきましたから。","ENG":"After all, I've spent a very long time chasing an angel.","TWN":"我追逐天使已經很久了。"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 예정대로 그들은 실패하고 말았죠.","JPN":"そして予定どおり彼らは失敗してしまったのです。","ENG":"As expected, they failed in the end.","TWN":"而且如預料的那樣，他們還是失敗了。"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L32_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"천사 강림이라고요?","JPN":"天使の降臨……？","ENG":"Descent of an angel?","TWN":"天使降臨嗎？"},"stage":{"bg":"THEATER","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신도 그 세계의 결말을 지켜보았으니, 알고 있을 텐데요?","JPN":"あなたもあの世界の結末を見届けたのだから、もうおわかりでしょう。","ENG":"You witnessed how that world ended. So you should already know.","TWN":"你也見證了那個世界的結局，應該知道吧？"},"stage":{"bg":"THEATER","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그자들은 인류의 구원을 원했습니다. 그리고 그 수단으로써 신성을 이용하려고 했어요.","JPN":"彼らは人類の救済を求めた。そしてその手段として、神聖を利用しようとしました。","ENG":"They sought salvation for humanity... and tried to use the Divinity as their means.","TWN":"他們希望拯救人類，並試圖利用神性作為手段。"},"stage":{"bg":"SS_DELTA_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"신성의 찌꺼기에 불과하지만, 그들은 변이 인자를 통해, 다른 존재가 되길 바랐으니까요.","JPN":"神聖の残りかすに過ぎないとはいえ、彼らは変異ファクターを通して別の存在になることを願った。","ENG":"It was nothing but a residue of the Divinity, but they still clung to the hope of becoming something more through the mutation factor.","TWN":"雖然只是神聖的殘渣，但他們透過變異因數，希望成為其他存在。"},"stage":{"bg":"SS_DELTA_02","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};